SELECT DISTINCT building_id
FROM water_samples
WHERE sample_status = 'completed';

SELECT AVG(lead_result) AS avg_lead, AVG(copper_result) AS avg_copper
FROM water_samples
WHERE building_id = 2;

SELECT building_id
FROM building_managers
WHERE user_id = 0;

SELECT DISTINCT building_id
FROM water_samples
ORDER BY building_id;

SELECT collection_date
FROM water_samples
WHERE building_id = 1;
